#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define N 1024
#define RADIUS 3

void stencil_1d(float *in, float *out, int n) {
#pragma omp parallel for
  for (int i = 0; i < n; i++) {
    float result = 0.f;
    for (int j = -RADIUS; j <= RADIUS; j++) {
      int idx = i + j;
      if (idx >= 0 && idx < n) {
        result += in[idx];
      }
    }
    out[i] = result;
  }
}

int main() {
  float *in = (float *)malloc(sizeof(float) * N);
  float *out = (float *)malloc(sizeof(float) * N);

  for (int i = 0; i < N; i++) {
    in[i] = i;
  }

  stencil_1d(in, out, N);

  for (int i = 0; i < 10; i++) {
    printf("out[%d] = %f\n", i, out[i]);
  }

  free(in);
  free(out);

  return 0;
}
